////////////////////////////////////////////////////////////////////////////////
//common/sabot_common.h
////////////////////////////////////////////////////////////////////////////////

// Common (hand-written) sabot functions should go here

// C doesn't have bools by default :(
#include "stdbool.h"

// for importing in Terra, don't need any special flags (e.g., declspec)
#define SABOT_EXPORT

// For clarity we typedef these so reading the API it's possible to tell what
// the expected size of a float array argument is
typedef float* f1_ptr;
typedef float* f3_ptr;
typedef float* f4_ptr;
typedef float* f16_ptr;

